import requests

# Kong Admin API base URL
admin_api_url = "http://localhost:8001"

# Create a service
service_data = {
    "name": "example-service",
    "url": "httpbin.org"
}
response = requests.post(f"{admin_api_url}/services", json=service_data)
service_id = response.json()["id"]

# Create an upstream target for the service
upstream_target_data = {
    "target": "127.0.0.1:8080"  # Example target
}
requests.post(f"{admin_api_url}/services/{service_id}/upstreams/targets", json=upstream_target_data)

# Create a route for the service
route_data = {
    "paths": ["/example"],
    "service": {"id": service_id}
}
requests.post(f"{admin_api_url}/routes", json=route_data)